// SVG placeholder images (replace with actual portfolio photos when deploying)
function placeholderSVG(label, bg = "#d4c4b0", fg = "#a08979") {
  const svg = `<svg xmlns='http://www.w3.org/2000/svg' width='600' height='750' viewBox='0 0 600 750'>
    <rect width='600' height='750' fill='${bg}'/>
    <g transform='translate(300,340)' opacity='0.4'>
      <rect x='-36' y='-30' width='72' height='60' rx='4' stroke='${fg}' stroke-width='2' fill='none'/>
      <circle cx='0' cy='-6' r='12' stroke='${fg}' stroke-width='2' fill='none'/>
      <polyline points='-36,30 -12,6 6,22 18,12 36,30' stroke='${fg}' stroke-width='2' fill='none'/>
    </g>
    <text x='300' y='420' text-anchor='middle' font-family='Georgia,serif' font-size='16' fill='${fg}' letter-spacing='4' opacity='0.5'>${label}</text>
  </svg>`;
  return `url("data:image/svg+xml,${encodeURIComponent(svg)}")`;
}

